selector_to_html = {"a[href=\"#lbm_caiman_python.validate_path\"]": "<dt class=\"sig sig-object py\" id=\"lbm_caiman_python.validate_path\">\n<span class=\"sig-prename descclassname\"><span class=\"pre\">lbm_caiman_python.</span></span><span class=\"sig-name descname\"><span class=\"pre\">validate_path</span></span><span class=\"sig-paren\">(</span><em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">path</span></span><span class=\"p\"><span class=\"pre\">:</span></span><span class=\"w\"> </span><span class=\"n\"><span class=\"pre\">str</span><span class=\"w\"> </span><span class=\"p\"><span class=\"pre\">|</span></span><span class=\"w\"> </span><span class=\"pre\">Path</span></span></em><span class=\"sig-paren\">)</span><a class=\"reference internal\" href=\"../_modules/lbm_caiman_python/batch.html#validate_path\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd></dd>", "a[href=\"#lbm_caiman_python.get_files\"]": "<dt class=\"sig sig-object py\" id=\"lbm_caiman_python.get_files\">\n<span class=\"sig-prename descclassname\"><span class=\"pre\">lbm_caiman_python.</span></span><span class=\"sig-name descname\"><span class=\"pre\">get_files</span></span><span class=\"sig-paren\">(</span><em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">pathnames</span></span><span class=\"p\"><span class=\"pre\">:</span></span><span class=\"w\"> </span><span class=\"n\"><span class=\"pre\">PathLike</span><span class=\"w\"> </span><span class=\"p\"><span class=\"pre\">|</span></span><span class=\"w\"> </span><span class=\"pre\">str</span><span class=\"w\"> </span><span class=\"p\"><span class=\"pre\">|</span></span><span class=\"w\"> </span><span class=\"pre\">list</span><span class=\"p\"><span class=\"pre\">[</span></span><span class=\"pre\">PathLike</span><span class=\"w\"> </span><span class=\"p\"><span class=\"pre\">|</span></span><span class=\"w\"> </span><span class=\"pre\">str</span><span class=\"p\"><span class=\"pre\">]</span></span></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">ext</span></span><span class=\"p\"><span class=\"pre\">:</span></span><span class=\"w\"> </span><span class=\"n\"><span class=\"pre\">str</span></span><span class=\"w\"> </span><span class=\"o\"><span class=\"pre\">=</span></span><span class=\"w\"> </span><span class=\"default_value\"><span class=\"pre\">'tif'</span></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">exclude_pattern</span></span><span class=\"p\"><span class=\"pre\">:</span></span><span class=\"w\"> </span><span class=\"n\"><span class=\"pre\">str</span></span><span class=\"w\"> </span><span class=\"o\"><span class=\"pre\">=</span></span><span class=\"w\"> </span><span class=\"default_value\"><span class=\"pre\">'_plane_'</span></span></em><span class=\"sig-paren\">)</span> <span class=\"sig-return\"><span class=\"sig-return-icon\">\u2192</span> <span class=\"sig-return-typehint\"><span class=\"pre\">list</span><span class=\"p\"><span class=\"pre\">[</span></span><span class=\"pre\">PathLike</span><span class=\"w\"> </span><span class=\"p\"><span class=\"pre\">|</span></span><span class=\"w\"> </span><span class=\"pre\">str</span><span class=\"p\"><span class=\"pre\">]</span></span><span class=\"w\"> </span><span class=\"p\"><span class=\"pre\">|</span></span><span class=\"w\"> </span><span class=\"pre\">PathLike</span></span></span><a class=\"reference internal\" href=\"../_modules/lbm_caiman_python/util/io.html#get_files\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd><p>Expands a list of pathname patterns to form a sorted list of absolute filenames.</p></dd>", "a[href=\"#lbm_caiman_python.plot_with_scalebars\"]": "<dt class=\"sig sig-object py\" id=\"lbm_caiman_python.plot_with_scalebars\">\n<span class=\"sig-prename descclassname\"><span class=\"pre\">lbm_caiman_python.</span></span><span class=\"sig-name descname\"><span class=\"pre\">plot_with_scalebars</span></span><span class=\"sig-paren\">(</span><em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">image</span></span><span class=\"p\"><span class=\"pre\">:</span></span><span class=\"w\"> </span><span class=\"n\"><span class=\"pre\">Any</span></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">pixel_resolution</span></span><span class=\"p\"><span class=\"pre\">:</span></span><span class=\"w\"> </span><span class=\"n\"><span class=\"pre\">float</span></span></em><span class=\"sig-paren\">)</span><a class=\"reference internal\" href=\"../_modules/lbm_caiman_python/helpers.html#plot_with_scalebars\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd><p>Plot a 2D image with scale bars of 5, 10, and 20 microns.</p></dd>", "a[href=\"#lbm_caiman_python.combine_z_planes\"]": "<dt class=\"sig sig-object py\" id=\"lbm_caiman_python.combine_z_planes\">\n<span class=\"sig-prename descclassname\"><span class=\"pre\">lbm_caiman_python.</span></span><span class=\"sig-name descname\"><span class=\"pre\">combine_z_planes</span></span><span class=\"sig-paren\">(</span><em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">results</span></span><span class=\"p\"><span class=\"pre\">:</span></span><span class=\"w\"> </span><span class=\"n\"><span class=\"pre\">dict</span></span></em><span class=\"sig-paren\">)</span><a class=\"reference internal\" href=\"../_modules/lbm_caiman_python/collation.html#combine_z_planes\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd><p>Combines all z-planes in the results dictionary into a single estimates object.</p></dd>", "a[href=\"#module-lbm_caiman_python\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">API<a class=\"headerlink\" href=\"#module-lbm_caiman_python\" title=\"Link to this heading\">#</a></h1>", "a[href=\"#lbm_caiman_python.concat_param_diffs\"]": "<dt class=\"sig sig-object py\" id=\"lbm_caiman_python.concat_param_diffs\">\n<span class=\"sig-prename descclassname\"><span class=\"pre\">lbm_caiman_python.</span></span><span class=\"sig-name descname\"><span class=\"pre\">concat_param_diffs</span></span><span class=\"sig-paren\">(</span><em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">input_df</span></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">param_diffs</span></span></em><span class=\"sig-paren\">)</span><a class=\"reference internal\" href=\"../_modules/lbm_caiman_python/helpers.html#concat_param_diffs\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd><p>Add parameter differences to the input DataFrame.</p><p class=\"rubric\">Examples</p></dd>", "a[href=\"#lbm_caiman_python.clean_batch\"]": "<dt class=\"sig sig-object py\" id=\"lbm_caiman_python.clean_batch\">\n<span class=\"sig-prename descclassname\"><span class=\"pre\">lbm_caiman_python.</span></span><span class=\"sig-name descname\"><span class=\"pre\">clean_batch</span></span><span class=\"sig-paren\">(</span><em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">df</span></span></em><span class=\"sig-paren\">)</span><a class=\"reference internal\" href=\"../_modules/lbm_caiman_python/batch.html#clean_batch\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd><p>Clean a batch of DataFrame entries by removing unsuccessful rows from storage.</p><p>This function iterates over the rows of the given DataFrame, identifies\nrows where the \u2018outputs\u2019 column is either <cite>None</cite> or a dictionary containing\na \u2018success\u2019 key with a <cite>False</cite> value. For each such row, the corresponding\nitem is removed using the <cite>df.caiman.remove_item()</cite> method, and the removal\nis saved to disk.</p><p class=\"rubric\">Notes</p><p class=\"rubric\">Examples</p></dd>", "a[href=\"#lbm_caiman_python.create_summary_df\"]": "<dt class=\"sig sig-object py\" id=\"lbm_caiman_python.create_summary_df\">\n<span class=\"sig-prename descclassname\"><span class=\"pre\">lbm_caiman_python.</span></span><span class=\"sig-name descname\"><span class=\"pre\">create_summary_df</span></span><span class=\"sig-paren\">(</span><em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">batch_df</span></span><span class=\"p\"><span class=\"pre\">:</span></span><span class=\"w\"> </span><span class=\"n\"><span class=\"pre\">DataFrame</span></span></em><span class=\"sig-paren\">)</span> <span class=\"sig-return\"><span class=\"sig-return-icon\">\u2192</span> <span class=\"sig-return-typehint\"><span class=\"pre\">DataFrame</span></span></span><a class=\"reference internal\" href=\"../_modules/lbm_caiman_python/helpers.html#create_summary_df\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd><p>Calculate summary statistics for each batch of image data and output results in a DataFrame.</p><p class=\"rubric\">Examples</p></dd>", "a[href=\"#lbm_caiman_python.plot_optical_flows\"]": "<dt class=\"sig sig-object py\" id=\"lbm_caiman_python.plot_optical_flows\">\n<span class=\"sig-prename descclassname\"><span class=\"pre\">lbm_caiman_python.</span></span><span class=\"sig-name descname\"><span class=\"pre\">plot_optical_flows</span></span><span class=\"sig-paren\">(</span><em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">input_df</span></span><span class=\"p\"><span class=\"pre\">:</span></span><span class=\"w\"> </span><span class=\"n\"><span class=\"pre\">DataFrame</span></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">max_columns</span></span><span class=\"o\"><span class=\"pre\">=</span></span><span class=\"default_value\"><span class=\"pre\">4</span></span></em><span class=\"sig-paren\">)</span><a class=\"reference internal\" href=\"../_modules/lbm_caiman_python/helpers.html#plot_optical_flows\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd><p>Plots the dense optical flow images from a DataFrame containing metrics information.</p><p class=\"rubric\">Examples</p></dd>", "a[href=\"#lbm_caiman_python.create_metrics_df\"]": "<dt class=\"sig sig-object py\" id=\"lbm_caiman_python.create_metrics_df\">\n<span class=\"sig-prename descclassname\"><span class=\"pre\">lbm_caiman_python.</span></span><span class=\"sig-name descname\"><span class=\"pre\">create_metrics_df</span></span><span class=\"sig-paren\">(</span><em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">metrics_filepaths</span></span><span class=\"p\"><span class=\"pre\">:</span></span><span class=\"w\"> </span><span class=\"n\"><span class=\"pre\">list</span><span class=\"p\"><span class=\"pre\">[</span></span><span class=\"pre\">str</span><span class=\"w\"> </span><span class=\"p\"><span class=\"pre\">|</span></span><span class=\"w\"> </span><span class=\"pre\">Path</span><span class=\"p\"><span class=\"pre\">]</span></span></span></em><span class=\"sig-paren\">)</span> <span class=\"sig-return\"><span class=\"sig-return-icon\">\u2192</span> <span class=\"sig-return-typehint\"><span class=\"pre\">DataFrame</span></span></span><a class=\"reference internal\" href=\"../_modules/lbm_caiman_python/helpers.html#create_metrics_df\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd><p>Create a DataFrame from a list of metrics files.</p><p class=\"rubric\">Examples</p></dd>", "a[href=\"#lbm_caiman_python.read_scan\"]": "<dt class=\"sig sig-object py\" id=\"lbm_caiman_python.read_scan\">\n<span class=\"sig-prename descclassname\"><span class=\"pre\">lbm_caiman_python.</span></span><span class=\"sig-name descname\"><span class=\"pre\">read_scan</span></span><span class=\"sig-paren\">(</span><em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">pathnames</span></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">dtype=&lt;class</span> <span class=\"pre\">'numpy.int16'&gt;</span></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">join_contiguous=False</span></span></em><span class=\"sig-paren\">)</span><a class=\"reference internal\" href=\"../_modules/scanreader/core.html#read_scan\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd><p>Reads a ScanImage scan.</p></dd>", "a[href=\"#lbm_caiman_python.save_as\"]": "<dt class=\"sig sig-object py\" id=\"lbm_caiman_python.save_as\">\n<span class=\"sig-prename descclassname\"><span class=\"pre\">lbm_caiman_python.</span></span><span class=\"sig-name descname\"><span class=\"pre\">save_as</span></span><span class=\"sig-paren\">(</span><em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">scan</span></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">savedir</span></span><span class=\"p\"><span class=\"pre\">:</span></span><span class=\"w\"> </span><span class=\"n\"><span class=\"pre\">PathLike</span></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">planes</span></span><span class=\"o\"><span class=\"pre\">=</span></span><span class=\"default_value\"><span class=\"pre\">None</span></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">frames</span></span><span class=\"o\"><span class=\"pre\">=</span></span><span class=\"default_value\"><span class=\"pre\">None</span></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">metadata</span></span><span class=\"o\"><span class=\"pre\">=</span></span><span class=\"default_value\"><span class=\"pre\">None</span></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">overwrite</span></span><span class=\"o\"><span class=\"pre\">=</span></span><span class=\"default_value\"><span class=\"pre\">True</span></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">ext</span></span><span class=\"o\"><span class=\"pre\">=</span></span><span class=\"default_value\"><span class=\"pre\">'.tiff'</span></span></em><span class=\"sig-paren\">)</span><a class=\"reference internal\" href=\"../_modules/lbm_caiman_python/assembly.html#save_as\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd><p>Save scan data to the specified directory in the desired format.</p><p class=\"rubric\">Notes</p><p>This function creates the specified directory if it does not already exist.\nData is saved per channel, organized by planes.</p></dd>", "a[href=\"#lbm_caiman_python.get_batch_from_path\"]": "<dt class=\"sig sig-object py\" id=\"lbm_caiman_python.get_batch_from_path\">\n<span class=\"sig-prename descclassname\"><span class=\"pre\">lbm_caiman_python.</span></span><span class=\"sig-name descname\"><span class=\"pre\">get_batch_from_path</span></span><span class=\"sig-paren\">(</span><em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">batch_path</span></span></em><span class=\"sig-paren\">)</span><a class=\"reference internal\" href=\"../_modules/lbm_caiman_python/batch.html#get_batch_from_path\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd><p>Load or create a batch at the given batch_path.</p></dd>", "a[href=\"#lbm_caiman_python.plot_residual_flows\"]": "<dt class=\"sig sig-object py\" id=\"lbm_caiman_python.plot_residual_flows\">\n<span class=\"sig-prename descclassname\"><span class=\"pre\">lbm_caiman_python.</span></span><span class=\"sig-name descname\"><span class=\"pre\">plot_residual_flows</span></span><span class=\"sig-paren\">(</span><em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">results</span></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">num_batches</span></span><span class=\"o\"><span class=\"pre\">=</span></span><span class=\"default_value\"><span class=\"pre\">3</span></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">smooth</span></span><span class=\"o\"><span class=\"pre\">=</span></span><span class=\"default_value\"><span class=\"pre\">True</span></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">winsize</span></span><span class=\"o\"><span class=\"pre\">=</span></span><span class=\"default_value\"><span class=\"pre\">5</span></span></em><span class=\"sig-paren\">)</span><a class=\"reference internal\" href=\"../_modules/lbm_caiman_python/helpers.html#plot_residual_flows\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd><p>Plot the top <cite>num_batches</cite> residual optical flows across batches.</p><p class=\"rubric\">Examples</p></dd>", "a[href=\"#lbm_caiman_python.default_ops\"]": "<dt class=\"sig sig-object py\" id=\"lbm_caiman_python.default_ops\">\n<span class=\"sig-prename descclassname\"><span class=\"pre\">lbm_caiman_python.</span></span><span class=\"sig-name descname\"><span class=\"pre\">default_ops</span></span><span class=\"sig-paren\">(</span><span class=\"sig-paren\">)</span><a class=\"reference internal\" href=\"../_modules/lbm_caiman_python/default_ops.html#default_ops\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd><p>Default parameters for both registration and CNMF.\nThe exception is gSiz being set relative to gSig.</p><p class=\"rubric\">Notes</p><p>This will likely change as CaImAn is updated.</p></dd>", "a[href=\"#lbm_caiman_python.fix_scan_phase\"]": "<dt class=\"sig sig-object py\" id=\"lbm_caiman_python.fix_scan_phase\">\n<span class=\"sig-prename descclassname\"><span class=\"pre\">lbm_caiman_python.</span></span><span class=\"sig-name descname\"><span class=\"pre\">fix_scan_phase</span></span><span class=\"sig-paren\">(</span><em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">data_in</span></span><span class=\"p\"><span class=\"pre\">:</span></span><span class=\"w\"> </span><span class=\"n\"><span class=\"pre\">ndarray</span></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">offset</span></span><span class=\"p\"><span class=\"pre\">:</span></span><span class=\"w\"> </span><span class=\"n\"><span class=\"pre\">int</span></span></em><span class=\"sig-paren\">)</span><a class=\"reference internal\" href=\"../_modules/lbm_caiman_python/assembly.html#fix_scan_phase\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd><p>Corrects the scan phase of the data based on a given offset along a specified dimension.</p></dd>", "a[href=\"#lbm_caiman_python.return_scan_offset\"]": "<dt class=\"sig sig-object py\" id=\"lbm_caiman_python.return_scan_offset\">\n<span class=\"sig-prename descclassname\"><span class=\"pre\">lbm_caiman_python.</span></span><span class=\"sig-name descname\"><span class=\"pre\">return_scan_offset</span></span><span class=\"sig-paren\">(</span><em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">image_in</span></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">nvals</span></span><span class=\"p\"><span class=\"pre\">:</span></span><span class=\"w\"> </span><span class=\"n\"><span class=\"pre\">int</span></span><span class=\"w\"> </span><span class=\"o\"><span class=\"pre\">=</span></span><span class=\"w\"> </span><span class=\"default_value\"><span class=\"pre\">8</span></span></em><span class=\"sig-paren\">)</span><a class=\"reference internal\" href=\"../_modules/lbm_caiman_python/assembly.html#return_scan_offset\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd><p>Compute the scan offset correction between interleaved lines or columns in an image.</p><p>This function calculates the scan offset correction by analyzing the cross-correlation\nbetween interleaved lines or columns of the input image. The cross-correlation peak\ndetermines the amount of offset between the lines or columns, which is then used to\ncorrect for any misalignment in the imaging process.</p><p class=\"rubric\">Notes</p><p>This function assumes that the input image contains interleaved lines or columns that\nneed to be analyzed for misalignment. The cross-correlation method is sensitive to\nthe similarity in pattern between the interleaved lines or columns. Hence, a strong\nand clear peak in the cross-correlation result indicates a good alignment, and the\ncorresponding lag value indicates the amount of misalignment.</p><p class=\"rubric\">Examples</p></dd>", "a[href=\"#lbm_caiman_python.delete_batch_rows\"]": "<dt class=\"sig sig-object py\" id=\"lbm_caiman_python.delete_batch_rows\">\n<span class=\"sig-prename descclassname\"><span class=\"pre\">lbm_caiman_python.</span></span><span class=\"sig-name descname\"><span class=\"pre\">delete_batch_rows</span></span><span class=\"sig-paren\">(</span><em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">df</span></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">rows_delete</span></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">remove_data</span></span><span class=\"o\"><span class=\"pre\">=</span></span><span class=\"default_value\"><span class=\"pre\">False</span></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">safe_removal</span></span><span class=\"o\"><span class=\"pre\">=</span></span><span class=\"default_value\"><span class=\"pre\">True</span></span></em><span class=\"sig-paren\">)</span><a class=\"reference internal\" href=\"../_modules/lbm_caiman_python/batch.html#delete_batch_rows\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd></dd>", "a[href=\"#lbm_caiman_python.compute_batch_metrics\"]": "<dt class=\"sig sig-object py\" id=\"lbm_caiman_python.compute_batch_metrics\">\n<span class=\"sig-prename descclassname\"><span class=\"pre\">lbm_caiman_python.</span></span><span class=\"sig-name descname\"><span class=\"pre\">compute_batch_metrics</span></span><span class=\"sig-paren\">(</span><em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">batch_df</span></span><span class=\"p\"><span class=\"pre\">:</span></span><span class=\"w\"> </span><span class=\"n\"><span class=\"pre\">DataFrame</span></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">overwrite</span></span><span class=\"p\"><span class=\"pre\">:</span></span><span class=\"w\"> </span><span class=\"n\"><span class=\"pre\">bool</span></span><span class=\"w\"> </span><span class=\"o\"><span class=\"pre\">=</span></span><span class=\"w\"> </span><span class=\"default_value\"><span class=\"pre\">False</span></span></em><span class=\"sig-paren\">)</span> <span class=\"sig-return\"><span class=\"sig-return-icon\">\u2192</span> <span class=\"sig-return-typehint\"><span class=\"pre\">List</span><span class=\"p\"><span class=\"pre\">[</span></span><span class=\"pre\">Path</span><span class=\"p\"><span class=\"pre\">]</span></span></span></span><a class=\"reference internal\" href=\"../_modules/lbm_caiman_python/helpers.html#compute_batch_metrics\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd><p>Compute and store various statistical metrics for each batch of image data.</p><p class=\"rubric\">Examples</p><p>TODO: This can be made to run in parallel.</p></dd>", "a[href=\"#lbm_caiman_python.plot_correlations\"]": "<dt class=\"sig sig-object py\" id=\"lbm_caiman_python.plot_correlations\">\n<span class=\"sig-prename descclassname\"><span class=\"pre\">lbm_caiman_python.</span></span><span class=\"sig-name descname\"><span class=\"pre\">plot_correlations</span></span><span class=\"sig-paren\">(</span><em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">results</span></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">num_batches</span></span><span class=\"o\"><span class=\"pre\">=</span></span><span class=\"default_value\"><span class=\"pre\">3</span></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">smooth</span></span><span class=\"o\"><span class=\"pre\">=</span></span><span class=\"default_value\"><span class=\"pre\">True</span></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">winsize</span></span><span class=\"o\"><span class=\"pre\">=</span></span><span class=\"default_value\"><span class=\"pre\">5</span></span></em><span class=\"sig-paren\">)</span><a class=\"reference internal\" href=\"../_modules/lbm_caiman_python/helpers.html#plot_correlations\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd><p>Plot the top <cite>num_batches</cite> batches with the highest correlation coefficients.</p></dd>", "a[href=\"#lbm_caiman_python.get_metadata\"]": "<dt class=\"sig sig-object py\" id=\"lbm_caiman_python.get_metadata\">\n<span class=\"sig-prename descclassname\"><span class=\"pre\">lbm_caiman_python.</span></span><span class=\"sig-name descname\"><span class=\"pre\">get_metadata</span></span><span class=\"sig-paren\">(</span><em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">file</span></span><span class=\"p\"><span class=\"pre\">:</span></span><span class=\"w\"> </span><span class=\"n\"><span class=\"pre\">PathLike</span><span class=\"w\"> </span><span class=\"p\"><span class=\"pre\">|</span></span><span class=\"w\"> </span><span class=\"pre\">str</span></span></em><span class=\"sig-paren\">)</span><a class=\"reference internal\" href=\"../_modules/lbm_caiman_python/util/io.html#get_metadata\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd><p>Extract metadata from a TIFF file. This can be a raw ScanImage TIFF or one\nprocessed via [lbm_caiman_python.save_as()](#save_as).</p></dd>", "a[href=\"#lbm_caiman_python.generate_patch_view\"]": "<dt class=\"sig sig-object py\" id=\"lbm_caiman_python.generate_patch_view\">\n<span class=\"sig-prename descclassname\"><span class=\"pre\">lbm_caiman_python.</span></span><span class=\"sig-name descname\"><span class=\"pre\">generate_patch_view</span></span><span class=\"sig-paren\">(</span><em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">image</span></span><span class=\"p\"><span class=\"pre\">:</span></span><span class=\"w\"> </span><span class=\"n\"><span class=\"pre\">Any</span></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">pixel_resolution</span></span><span class=\"p\"><span class=\"pre\">:</span></span><span class=\"w\"> </span><span class=\"n\"><span class=\"pre\">float</span></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">target_patch_size</span></span><span class=\"p\"><span class=\"pre\">:</span></span><span class=\"w\"> </span><span class=\"n\"><span class=\"pre\">int</span></span><span class=\"w\"> </span><span class=\"o\"><span class=\"pre\">=</span></span><span class=\"w\"> </span><span class=\"default_value\"><span class=\"pre\">40</span></span></em>, <em class=\"sig-param\"><span class=\"n\"><span class=\"pre\">overlap_fraction</span></span><span class=\"p\"><span class=\"pre\">:</span></span><span class=\"w\"> </span><span class=\"n\"><span class=\"pre\">float</span></span><span class=\"w\"> </span><span class=\"o\"><span class=\"pre\">=</span></span><span class=\"w\"> </span><span class=\"default_value\"><span class=\"pre\">0.5</span></span></em><span class=\"sig-paren\">)</span><a class=\"reference internal\" href=\"../_modules/lbm_caiman_python/helpers.html#generate_patch_view\"><span class=\"viewcode-link\"><span class=\"pre\">[source]</span></span></a></dt><dd><p>Generate a patch visualization for a 2D image with approximately square patches of a specified size in microns.\nPatches are evenly distributed across the image, using calculated strides and overlaps.</p><p class=\"rubric\">Examples</p></dd>"}
skip_classes = ["headerlink", "sd-stretched-link"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(` ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: true,
                placement: 'auto-start', maxWidth: 500, interactive: false,

            });
        };
    };
    console.log("tippy tips loaded!");
};
